VALUES
  ('disabled-23e15ae5-moex-00330', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '承上題，文中指出：「解決問題像爬階梯」，這句話意指：', '["發明是發明家的專利", "創意等待我們去發現", "問題如雪崩般一次湧入", "不同層次面對不同問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00331', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '下列對聯，何者最能表現出藉景物自我勉勵之意？', '["清泉稱人意，古巷烹茶香", "柳堆千疊綠，泉湧一池春", "江山開眼界，風雪煉精神", "柳浪煙竹畫，湖山藕荷詩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00332', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '在〈卡債與旅行的意義〉這首詩中有以下的句子：「對不起我只能盡最低 應盡責任╱因為我只繳得起最低應繳金額╱美景我們都看過了╱你們也 看過了就好╱在螢幕上看也差不多╱美食可以看看就好╱只要餓了什麼 都好吃╱吃進肚子裡也差不多」下列選項，何者最符合本詩的意旨？', '["在螢幕上看美景、賞美食，也別有一番情趣", "連卡債都還不清，更遑論旅行賞美景、吃美食", "即使償還卡債很吃力，仍然要賞美景、吃美食", "每月繳交最低應繳金額，就是作者最盡責的表現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00333', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '魯有執長竿入城門者，初豎執之，不可入；橫執之，亦不可入，計無所出。 俄有老父至曰：「吾非聖人，但見事多矣。何不以鋸中截而入？」遂依而 截之。（邯鄲淳《笑林》）此笑話之啟示在於：', '["人謀不臧，道謀是用", "毋必毋固，通權而達變", "不語海於井蛙，不語冰於夏蟲", "學而不思則罔，思而不學則殆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00334', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「我不和你談論詩藝╱不和你談論那些糾纏不清的隱喻╱請離開書房╱ 我帶你去廣袤的田野走走╱去看看遍處的幼苗╱如何沉默地奮力生長」 下列何者最接近本詩的意思？', '["空言藝術美感，不如親身去體驗鄉土", "幼苗在無人關注的所在，仍奮力生長", "在書房閉門討論詩藝，有助提升造詣", "唯有寫作詩歌，才能頌讚土地的美好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00335', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「當我驚醒／當年輕的夢被午夜驚醒／被及胸的風／與花與雪與月／驚 醒／白髮，我聽到你一根／又一根裂膚而出的聲音」下列敘述，最符合詩 意的是：', '["為青春已逝而喟嘆", "以淡定心情看待歲月", "奉勸世人要及時努力", "後悔年輕時沉溺於風花雪月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00336', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「人生終需一死，絕症病人的死亡，並非醫療的失敗；未能協助病人安詳 往生，才是醫療的失敗。活著，是最好的禮物；善終，是最美的祝福！」 根據上文，下列選項最符合本文旨意的是：', '["減輕死亡的痛苦也屬於醫療的成功", "醫生治療病患皆以善終為最好祝福", "醫療的失敗是沒辦法挽救病患生命", "最好的禮物是讓每個人都能活下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00337', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「在人生奔馳多變的旅程中，心中的那座山將沉甸甸地給你依靠著，在困 頓消沉的逆境時，心中的那座山將高聳地屹立著給你鼓舞的指標。整個世 界都在匆忙地趕路，惟有大屯山毅然挺身而出，不隨波逐流，不輕易更改 容顏。」下列何者最接近本文對山的描述？', '["堅毅不拔", "堅苦卓絕", "無堅不摧", "鑽堅仰高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00338', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「教育是一種雙向的互動過程，施教者和受教者都必須盡到自己份內該盡 的責任與義務，懂得知不足而後自反，體悟知困而能自強。」下列何者是 作者所要表達的意思？', '["化民成俗", "因材施教", "百年樹人", "教學相長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00339', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-110-01c5eaab', 'sub-disabled-23e15ae5-03', NULL, 'single_choice', '「當愛落到行為層面，就要求『愛到』的效果，這叫做『義』。義很難一 發就正中紅心，總須在行為模式的兩極端間揣摩斟酌權衡，這叫做『辨義』 或『擇義』。」根據上文，下列何者符合作者的看法？', '["心中有愛就能充分地體現「義」", "是非分明就是「辨義」的具體表現", "對人表達一己的善意，就叫做「義」", "「擇義」是為了達到「愛到」的效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:48+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "503", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
